SELECT b.*, u.nickname as student_name, c.course_name, CASE WHEN b.behavior_type = 'VIDEO_WATCH' THEN '观看视频' WHEN b.behavior_type = 'RESOURCE_DOWNLOAD' THEN '资源下载' WHEN b.behavior_type = 'ASSIGNMENT_SUBMIT' THEN '提交作业' WHEN b.behavior_type = 'FORUM_PARTICIPATE' THEN '论坛参与' WHEN b.behavior_type = 'QUIZ_COMPLETE' THEN '完成测验' ELSE b.behavior_type END as description FROM stat_learning_behavior b LEFT JOIN edu_student s ON b.student_id = s.student_id LEFT JOIN sys_user u ON s.user_id = u.user_id LEFT JOIN edu_course c ON b.course_id = c.course_id WHERE 1=1
AND b.student_id = #{studentId}
AND b.course_id = #{courseId}
AND b.behavior_type = #{behaviorType}
AND b.behavior_time >= #{startTime}
AND b.behavior_time <= #{endTime}
ORDER BY b.behavior_time DESC

SELECT COUNT(*)
FROM stat_learning_behavior
WHERE 1=1

    AND student_id = #{studentId}


    AND course_id = #{courseId}


    AND behavior_type = #{behaviorType}


    AND behavior_time >= #{startTime}


    AND behavior_time <= #{endTime}

SELECT COALESCE(SUM(duration), 0) / 60
FROM stat_learning_behavior
WHERE behavior_type = 'view_resource'

    AND student_id = #{studentId}


    AND course_id = #{courseId}


    AND behavior_time >= #{startTime}


    AND behavior_time <= #{endTime}
